<?php/DevelopmentErrorReportingif(!defined('DEVELOPMENT_MODE')){error_reporting(E_ALL);ini_set('display_errors',1);ini_set('display_startup_errors',1);}declare(strict_types=1);/***UniversalAPIAuthenticationHelper*ProvidesconsistentauthenticationacrossallAPIendpoints*/require_once'../core/config.php';classAPIAuth{privatestatic$instance=null;private$user=null;private$authenticated=false;publicstaticfunctiongetInstance(){if(self::$instance===null){self::$instance=newself();}returnself::$instance;}privatefunction__construct(){$this->validateSession();}/***Validatesessionandauthenticateuser*/privatefunctionvalidateSession(){/Startsessionifnotstartedif(session_status()===PHP_SESSION_NONE){session_start();}/Checkifuserisloggedinif(isset($_SESSION['user_id'])&&!empty($_SESSION['user_id'])){$this->authenticated=true;$this->user=['id'=>$_SESSION['user_id'],'username'=>$_SESSION['username']??'','role'=>$_SESSION['user_role']??'user'];}}/***Checkifuserisauthenticated*/publicfunctionisAuthenticated(){return$this->authenticated;}/***Getcurrentuserdata*/publicfunctiongetUser(){return$this->user;}/***Requireauthentication-returnserrorresponseifnotauthenticated*/publicfunctionrequireAuth(){if(!$this->authenticated){$this->sendAuthError();exit;}}/***Checkifuserhasspecificrole*/publicfunctionhasRole($role){if(!$this->authenticated){returnfalse;}return$this->user['role']===$role;}/***Requirespecificrole*/publicfunctionrequireRole($role){if(!$this->hasRole($role)){$this->sendError('Insufficientpermissions',403);exit;}}/***Sendauthenticationerrorresponse*/privatefunctionsendAuthError(){header('HTTP/1.0401Unauthorized');header('Content-Type:application/json');echojson_encode(['success'=>false,'message'=>'Unauthorized-Sessionnotvalid','error_code'=>401,'details'=>[],'timestamp'=>date('c'),'meta'=>['version'=>APP_VERSION,'environment'=>ENVIRONMENT]]);}/***Sendgeneralerrorresponse*/publicfunctionsendError($message,$code=400,$details=[]){header("HTTP/1.0$code".$this->getStatusText($code));header('Content-Type:application/json');echojson_encode(['success'=>false,'message'=>$message,'error_code'=>$code,'details'=>$details,'timestamp'=>date('c'),'meta'=>['version'=>APP_VERSION,'environment'=>ENVIRONMENT]]);}/***Sendsuccessresponse*/publicfunctionsendSuccess($data=null,$message='Operationsuccessful'){header('Content-Type:application/json');$response=['success'=>true,'message'=>$message,'timestamp'=>date('c'),'meta'=>['version'=>APP_VERSION,'environment'=>ENVIRONMENT]];if($data!==null){$response['data']=$data;}echojson_encode($response);}/***GetHTTPstatustext*/privatefunctiongetStatusText($code){$statusTexts=[200=>'OK',400=>'BadRequest',401=>'Unauthorized',403=>'Forbidden',404=>'NotFound',500=>'InternalServerError'];return$statusTexts[$code]??'Unknown';}/***Validaterequestmethod*/publicfunctionvalidateMethod($allowedMethods=['GET','POST']){$method=$_SERVER['REQUEST_METHOD'];if(!in_array($method,$allowedMethods)){$this->sendError("Method$methodnotallowed",405);exit;}return$method;}/***Getandsanitizeinputdata*/publicfunctiongetInputData(){$method=$_SERVER['REQUEST_METHOD'];switch($method){case'GET':return$_GET;case'POST':return$_POST;case'PUT':case'DELETE':parse_str(file_get_contents('php://input'),$data);return$data;default:return[];}}/***Validaterequiredfields*/publicfunctionvalidateRequired($data,$requiredFields){$missing=[];forforeach($requiredFieldsas$field){if(!isset($data[$field])||empty($data[$field])){$missing[]=$field;}}if(!empty($missing)){$this->sendError('Missingrequiredfields',400,$missing);exit;}returntrue;}/***Sanitizeinputdata*/publicfunctionsanitizeData($data){$sanitized=[];forforeach($dataas$key=>$value){if(is_array($value)){$sanitized[$key]=$this->sanitizeData($value);}else{$sanitized[$key]=htmlspecialchars(trim($value),ENT_QUOTES,'UTF-8');}}return$sanitized;}/***LogAPIactivity*/publicfunctionlogActivity($action,$details=[]){$logEntry=['timestamp'=>date('c'),'user_id'=>$this->user['id']??null,'username'=>$this->user['username']??null,'action'=>$action,'details'=>$details,'ip'=>$_SERVER['REMOTE_ADDR']??'unknown','user_agent'=>$_SERVER['HTTP_USER_AGENT']??'unknown'];$logFile=ROOT_PATH.'/logs/api_activity.log';$logLine=json_encode($logEntry)."\n";file_put_contents($logFile,$logLine,FILE_APPEND|LOCK_EX);}}/HelperfunctionforquickaccessfunctiongetAPIAuth(){returnAPIAuth::getInstance();}?>
